#include<cstdio>
#include<algorithm>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=1e5+10;int P[N],p,a[N],c[N],n,m,ans,b[N],A[N];
inline int bnd(int k){int l(1),r(p),m;while(l<=r)P[m=(l+r)>>1]<=k?l=m+1:r=m-1;return l-1;}
int main()
{
	m=read();n=read();rep(1,m,i)b[i]=read();rep(1,n,i)A[i]=P[i]=read();
	std::sort(P+1,P+n+1);p=std::unique(P+1,P+n+1)-P-1;rep(1,n,i)++a[bnd(A[i])];
	rep(1,m,i){int x=b[i];drep(p,1,i){while(x>=P[i]){x-=P[i];++c[i];}}}
//	rep(1,p,i)printf("%d ",P[i]);puts("");
//	rep(1,p,i)printf("%d ",a[i]);puts("");
//	rep(1,p,i)printf("%d ",c[i]);puts("");
	rep(1,p,i)
	{
		while(a[i])
		{
			if(!c[i]){rep(i+1,p,j){if(c[j]){c[i]+=P[j]/P[i];--c[j];break;}}}
			if(c[i])++ans,--c[i],--a[i];else break;
		}
	}
	printf("%d\n",ans);return 0;
}
